import { AutocompleteInput } from "@/components/ra-wrappers/autocomplete-input";
import { getQSearchAutocompleteProps } from "@/atomic-crm/utils/autocompleteDefaults";
import { QuickCreateOrganizationRA } from "./QuickCreatePopover";

export const AutocompleteOrganizationInput = ({
  label,
  organizationType,
  helperText,
  source,
}: {
  label?: string;
  organizationType?: string;
  helperText?: string | false;
  source?: string;
}) => {
  return (
    <AutocompleteInput
      {...getQSearchAutocompleteProps()}
      source={source}
      optionText="name"
      helperText={helperText}
      create={
        <QuickCreateOrganizationRA
          organizationType={
            (organizationType as "customer" | "prospect" | "principal" | "distributor") ||
            "customer"
          }
        />
      }
      createItemLabel="Create %{item}"
      label={label}
    />
  );
};
